private static final String BASE62 = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";

public String toBase62(long id) {
    StringBuilder sb = new StringBuilder();
    while (id > 0) {
        sb.append(BASE62.charAt((int)(id % 62)));
        id /= 62;
    }
    return sb.reverse().toString();
}

public String resolve(String alias) {
    String url = redis.get(alias);
    if (url != null) return url;

    UrlMapping mapping = db.findByAlias(alias);
    if (mapping == null) throw new NotFoundException();

    long ttl = mapping.getExpiresAt() - Instant.now().getEpochSecond();
    if (ttl > 0) redis.setex(alias, ttl, mapping.getLongUrl());
    return mapping.getLongUrl();
}

@PostMapping("/shorten")
public ResponseEntity<ShortenResponse> shorten(@RequestBody ShortenRequest req) {
    String alias = req.getCustomAlias() != null
        ? req.getCustomAlias()
        : base62Encode(idGenerator.nextId());

    db.save(new UrlMapping(alias, req.getLongUrl(),
        Instant.now().plus(req.getTtlDays(), DAYS)));

    return ResponseEntity.status(201)
        .body(new ShortenResponse("https://short.ly/" + alias));
}
